BEGIN TRANSACTION;
CREATE TABLE "bookings_raw" (
"booking_id" INTEGER,
  "customer_id" INTEGER,
  "city" TEXT,
  "unit_size" TEXT,
  "start_date" TEXT,
  "end_date" TEXT,
  "duration_months" INTEGER,
  "monthly_price" REAL,
  "total_revenue" REAL,
  "channel" TEXT,
  "repeat_customer" INTEGER
);
CREATE TABLE "dim_city" (
"city" TEXT,
  "city_id" INTEGER
);
CREATE TABLE "dim_unit" (
"unit_size" TEXT,
  "monthly_price" REAL,
  "unit_id" INTEGER
);
CREATE TABLE "fact_bookings" (
"booking_id" INTEGER,
  "customer_id" INTEGER,
  "city_id" INTEGER,
  "unit_id" INTEGER,
  "duration_months" INTEGER,
  "monthly_price" REAL,
  "total_revenue" REAL,
  "repeat_customer" INTEGER
);
CREATE TABLE "feedback_raw" (
"city" TEXT,
  "month" TEXT,
  "year" INTEGER,
  "rating" INTEGER,
  "comment" TEXT
);
CREATE TABLE "weather_raw" (
"city" TEXT,
  "year" INTEGER,
  "month" INTEGER,
  "avg_temp" REAL
);
COMMIT;
